import 'package:flutter_test/flutter_test.dart';

/// Shared behavior contract for generated escape-time module smoke tests.
///
/// Keeps per-module tests focused on the module identity while preserving the
/// same public assertions that each generated smoke test performed inline.
void expectEscapeTimeModuleSmoke({
  required dynamic module,
  required String id,
  required String shader,
}) {
  expect(module.id, id);
  expect(module.shader, shader);
  expect(module.presets, isNotEmpty);
  for (final p in module.presets) {
    expect(p.id, isNotEmpty);
    expect(p.name, isNotEmpty);
  }
  expect(module.metadata.id, module.id);
}

